WITH ship AS (SELECT CAST(asin AS TEXT) AS asin, MAX(item_name) AS item_name, SUM(shipped_units) AS shipped_units FROM shipped_raw GROUP BY CAST(asin AS TEXT)), conc AS (SELECT CAST(asin AS TEXT) AS asin, SUM(conceded_units) AS conceded_units FROM concession_raw GROUP BY CAST(asin AS TEXT)) SELECT sh.asin, sh.item_name, sh.shipped_units, COALESCE(co.conceded_units, 0) AS conceded_units FROM ship sh LEFT JOIN conc co ON co.asin = sh.asin WHERE sh.shipped_units > 0 ORDER BY COALESCE(co.conceded_units, 0) ASC NULLS LAST LIMIT 1;